const raw = $input.first().json.content?.[0]?.text || '{}';

let parsed = {};
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { raw_analysis: raw };
}

return [{ json: {
  status: 'completed',
  workflow: '14_database_health_report',
  summary: parsed.summary || 'Health analysis complete',
  health_score: parsed.health_score || 'N/A',
  table_analysis: parsed.table_analysis || [],
  growth_trends: parsed.growth_trends || [],
  potential_issues: parsed.potential_issues || [],
  optimization_suggestions: parsed.optimization_suggestions || [],
  capacity_forecast: parsed.capacity_forecast || 'N/A',
  recommendations: parsed.recommendations || [],
  report: parsed,
  completedAt: new Date().toISOString()
} }];
